module top_module(
    input [7:0] min_val,
    input [7:0] b,
    output reg [7:0] max,
    output reg equal_flag
);always @(*) begin
    if (min_val > b) begin
        max = min_val;
        equal_flag = 0;
    end
    else if (b > min_val) begin
        max = b;
        equal_flag = 0;
    end
    else begin
        max = min_val;
        equal_flag = 1;
    end
end

endmodule
